# ── Flatline heartbeat (no-op if running standalone) ─────────────────────
try:
    from source.remote_client import RemoteClient as _Remote
    _FL = _Remote()
except Exception:
    class _Null:
        def beat(self, *a, **kw): pass
    _FL = _Null()

def _beat(reason: str = "TICK", caller: str = "") -> None:
    try: _FL.beat(reason, caller)
    except Exception: pass

