# ── Browser helper ────────────────────────────────────────────────────────
def open_help() -> None:
    """Open help.html in Chrome/Firefox; fallback to system default."""
    html = HERE / "help.html"
    import subprocess
    url = html.as_uri() if html.exists() else "https://flatline.triodesktop.com/"
    # Try Chrome then Firefox before falling back to webbrowser
    candidates = []
    if sys.platform == "win32":
        import os
        candidates += [
            r"C:\Program Files\Google\Chrome\Application\chrome.exe",
            r"C:\Program Files (x86)\Google\Chrome\Application\chrome.exe",
            r"C:\Program Files\Mozilla Firefox\firefox.exe",
            r"C:\Program Files (x86)\Mozilla Firefox\firefox.exe",
        ]
        local = os.environ.get("LOCALAPPDATA","")
        if local:
            candidates.append(os.path.join(local,"Google","Chrome","Application","chrome.exe"))
        try:
            import winreg
            for root in (winreg.HKEY_LOCAL_MACHINE, winreg.HKEY_CURRENT_USER):
                for exe in ("chrome.exe","firefox.exe"):
                    key = rf"SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths\{exe}"
                    try:
                        with winreg.OpenKey(root, key) as k:
                            path, _ = winreg.QueryValueEx(k,"")
                            if path: candidates.insert(0, path)
                    except Exception: pass
        except ImportError: pass
    elif sys.platform == "darwin":
        candidates += [
            "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
            "/Applications/Firefox.app/Contents/MacOS/firefox",
        ]
    else:
        import shutil
        for name in ("google-chrome","chromium-browser","firefox"):
            p = shutil.which(name)
            if p: candidates.append(p)
    for c in candidates:
        if os.path.isfile(c):
            try:
                subprocess.Popen([c, url], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
                return
            except Exception: pass
    webbrowser.open(url)

