# ── Main window ───────────────────────────────────────────────────────────
class AppWindow(QMainWindow):
    def __init__(self):
        super().__init__()
        _beat("INIT", "AppWindow")
        self.setWindowTitle("Flatline Demo — Code Runner")
        self.resize(1200, 700)
        self._running = False
        self._buildUi()
        self._buildMenu()
        _beat("READY", "AppWindow")

    def _buildUi(self) -> None:
        central = QWidget()
        self.setCentralWidget(central)
        central.setStyleSheet("QWidget { background: #0a0a0a; }")

        root = QVBoxLayout(central)
        root.setContentsMargins(8, 8, 8, 8)
        root.setSpacing(6)

        # ── Splitter ────────────────────────────────────────────────────
        splitter = QSplitter(Qt.Orientation.Horizontal)
        splitter.setHandleWidth(6)
        splitter.setStyleSheet("QSplitter::handle { background: #1a1a1a; }")

        # Left: white monospaced code editor
        editor_wrap = QWidget()
        editor_wrap.setStyleSheet("QWidget { background: #0a0a0a; }")
        el = QVBoxLayout(editor_wrap)
        el.setContentsMargins(0, 0, 0, 0)
        el.setSpacing(2)

        editor_label = QLabel("Code Editor")
        editor_label.setStyleSheet("color:#888;font-size:10px;padding:2px 4px;")
        el.addWidget(editor_label)

        self.editor = QPlainTextEdit()
        self.editor.setPlainText(DEFAULT_CODE)
        self.editor.setFont(QFont("Courier New", 11))
        self.editor.setStyleSheet("""
            QPlainTextEdit {
                background: #ffffff;
                color: #1a1a1a;
                border: 1px solid #444;
                border-radius: 4px;
                padding: 8px;
            }
        """)

        # Watermark: transparent logo in bottom-right of editor
        # (placed as a QLabel overlay — positioned after show())
        self._watermark = QLabel(editor_wrap)
        self._watermark.setAlignment(Qt.AlignmentFlag.AlignCenter)
        try:
            ba = QByteArray.fromBase64(FLATLINE_PNG.encode())
            img = QImage.fromData(ba, "JPEG")
            pix = QPixmap.fromImage(img).scaledToWidth(180, Qt.TransformationMode.SmoothTransformation)
            self._watermark.setPixmap(pix)
            self._watermark.setStyleSheet("background:transparent; opacity:0.12;")
            self._watermark.setFixedSize(pix.width(), pix.height())
        except Exception:
            self._watermark = None

        el.addWidget(self.editor)

        # Right: black / green-border output console
        output_wrap = QWidget()
        output_wrap.setStyleSheet("QWidget { background: #0a0a0a; }")
        ol = QVBoxLayout(output_wrap)
        ol.setContentsMargins(0, 0, 0, 0)
        ol.setSpacing(2)

        output_label = QLabel("Output")
        output_label.setStyleSheet("color:#00c853;font-size:10px;padding:2px 4px;")
        ol.addWidget(output_label)

        self.output = QTextEdit()
        self.output.setReadOnly(True)
        self.output.setFont(QFont("Courier New", 10))
        self.output.setStyleSheet("""
            QTextEdit {
                background: #0d0d0d;
                color: #00e676;
                border: 2px solid #00c853;
                border-radius: 4px;
                padding: 8px;
            }
        """)
        ol.addWidget(self.output)

        splitter.addWidget(editor_wrap)
        splitter.addWidget(output_wrap)
        splitter.setSizes([580, 580])
        root.addWidget(splitter, 1)   # stretch=1: takes all available height

        # ── Button row (fixed height) ──────────────────────────────────
        btn_row = QHBoxLayout()
        btn_row.setSpacing(8)

        self.runBtn = QPushButton("▶  Run Code")
        self.runBtn.setFixedHeight(34)
        self.runBtn.setStyleSheet("""
            QPushButton {
                background:#c0392b; color:#fff; border:none;
                border-radius:4px; font-size:13px; font-weight:bold;
                padding:0 18px;
            }
            QPushButton:hover   { background:#a93226; }
            QPushButton:pressed { background:#922b21; }
            QPushButton:disabled{ background:#555; color:#888; }
        """)
        self.runBtn.clicked.connect(self._run)

        self.clearBtn = QPushButton("Clear Output")
        self.clearBtn.setFixedHeight(34)
        self.clearBtn.setStyleSheet("""
            QPushButton {
                background:#111; color:#00e676; border:1px solid #00c853;
                border-radius:4px; font-size:12px; padding:0 14px;
            }
            QPushButton:hover { background:#1a1a1a; }
        """)
        self.clearBtn.clicked.connect(self.output.clear)

        self.statusLbl = QLabel("Ready.")
        self.statusLbl.setStyleSheet("color:#555; font-size:11px;")

        btn_row.addWidget(self.runBtn)
        btn_row.addWidget(self.clearBtn)
        btn_row.addStretch()
        btn_row.addWidget(self.statusLbl)
        root.addLayout(btn_row)

    def showEvent(self, event):
        super().showEvent(event)
        _beat("SHOW", "AppWindow")
        # Position watermark bottom-right of editor
        if self._watermark:
            try:
                QTimer.singleShot(100, self._positionWatermark)
            except Exception:
                pass

    def resizeEvent(self, event):
        super().resizeEvent(event)
        _beat("RESIZE", "AppWindow")
        if self._watermark:
            try:
                self._positionWatermark()
            except Exception:
                pass

    def _positionWatermark(self) -> None:
        if not self._watermark:
            return
        try:
            ed = self.editor
            pw = self._watermark.width()
            ph = self._watermark.height()
            # Position in bottom-right of editor, with 12px margin
            x = ed.x() + ed.width()  - pw - 12
            y = ed.y() + ed.height() - ph - 12
            self._watermark.move(x, y)
            self._watermark.raise_()
        except Exception:
            pass

    def _buildMenu(self) -> None:
        bar = self.menuBar()
        bar.setStyleSheet("""
            QMenuBar { background:#0a0a0a; color:#ccc; }
            QMenuBar::item:selected { background:#c0392b; color:#fff; }
            QMenu { background:#111; color:#ccc; border:1px solid #333; }
            QMenu::item:selected { background:#c0392b; }
        """)
        file_menu = bar.addMenu("&File")
        close_act = QAction("&Close", self)
        close_act.setShortcut("Ctrl+Q")
        close_act.triggered.connect(self.close)
        file_menu.addAction(close_act)

        help_menu = bar.addMenu("&Help")
        help_act = QAction("&Help", self)
        help_act.setShortcut("F1")
        help_act.triggered.connect(self._openHelp)
        help_menu.addAction(help_act)
        help_menu.addSeparator()
        about_act = QAction("&About", self)
        about_act.triggered.connect(self._showAbout)
        help_menu.addAction(about_act)

    def _openHelp(self) -> None:
        _beat("HELP", "AppWindow")
        open_help()

    def _showAbout(self) -> None:
        _beat("ABOUT", "AppWindow")
        dlg = AboutDialog(self)
        dlg.exec()

    def _run(self) -> None:
        if self._running:
            return
        _beat("RUN", "AppWindow")
        code_text = self.editor.toPlainText()
        if not code_text.strip():
            self.output.append("<i>Nothing to run.</i>")
            return
        self.output.clear()
        self.output.append("=== Running ===\n")
        self.runBtn.setEnabled(False)
        self._running = True
        self.statusLbl.setText("Running...")

        out_panel = self.output

        def _print(*args, sep=" ", end="\n", **kwargs):
            text = sep.join(str(a) for a in args)
            out_panel.append(text)

        sandbox = {
            "__name__": "__flatline_sandbox__",
            "__builtins__": __builtins__,
            "print": _print,
            "flatline_output": out_panel,
        }

        def _exec():
            try:
                exec(compile(code_text, "<flatline_editor>", "exec"), sandbox)
                QTimer.singleShot(0, lambda: self._done(None))
            except Exception as e:
                import traceback as _tb
                err = f"[ERROR] {type(e).__name__}: {e}\n{_tb.format_exc()}"
                QTimer.singleShot(0, lambda: self._done(err))

        threading.Thread(target=_exec, name="FlatlineCodeRunner", daemon=True).start()

    def _done(self, error: str | None) -> None:
        self._running = False
        self.runBtn.setEnabled(True)
        if error:
            _beat("CRASH", "AppWindow")
            self.output.append(f"\n{error}")
            self.statusLbl.setText("Error — see output")
        else:
            _beat("RUN_DONE", "AppWindow")
            self.output.append("\n=== Done ===")
            self.statusLbl.setText("Done.")

    def closeEvent(self, event):
        _beat("CLOSE", "AppWindow")
        event.accept()


def main() -> int:
    app = QApplication(sys.argv)
    app.setApplicationName("Flatline Demo")
    app.setOrganizationName("Trent Tompkins")
    win = AppWindow()
    win.show()
    return app.exec()


if __name__ == "__main__":
    sys.exit(main())
